module shift_reg4bit(
    input clk,
    input load,
    input [3:0] data_in,

    output reg [3:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        q <= data_in;
    else
        q <= {1'b0, q[3:1]};
end

endmodule
